window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q19"]=window.__LIBQ["tien-nghich"]["q19"]||{};window.__LIBQ["tien-nghich"]["q19"]["techniques"]={"updatedAt":"2026-07-16","count":49,"techniques":[{"id":"an-quyet-dac-thu-che-giau-than-thuc","name":"Ấn quyết đặc thù che giấu thần thức","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Ấn quyết","phamCap":"Không rõ","hePhai":"Tiên Tổ truyền xuống","soHuu":["Vương Lâm","Tiên Tổ"],"blurb":"Ấn quyết dùng để che giấu dao động thần thức khi Thiên Tôn tiến vào Thiên Tôn Niết.","detail":"Vương Lâm thi triển ấn quyết này khi ngưng tụ thần thức trên thiên linh. Ấn quyết có tác dụng ẩn đi mọi dao động thần thức, giúp Thiên Tôn tiến vào Thiên Tôn Niết mà không bị người khác phát hiện; theo lời truyền, nó do Tiên Tổ truyền xuống.","thuocTinh":"Che giấu thần thức","nguonGoc":"Tiên Tổ truyền xuống","congNang":["Ẩn giấu mọi dao động của thần thức khi tiến vào Thiên Tôn Niết @c1832"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1832","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1832","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm thử vào Thiên Tôn Niết","text":"Vương Lâm dùng ấn quyết để che giấu dao động thần thức trước khi thần thức rời thân tiến vào Thiên Nhân suy kiếp.","anchor":"chính là có tác dụng ẩn dấu mọi giao động của thần thức"}]},"capNhatToi":"@c1832","nguon":["@c1832"]},{"id":"truyen-tong-tran-co-xua-trong-thien-nhan-suy-kiep","name":"Truyền Tống Trận cổ xưa trong Thiên Nhân suy kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Nhân suy kiếp","soHuu":[],"blurb":"Trận pháp cổ xưa trên đại lục lơ lửng trong Thiên Nhân suy kiếp, nơi Vương Lâm xuất hiện sau khi thần thức bị hút vào.","detail":"Trận pháp này rất phức tạp, đặt trên đại lục lơ lửng trong Thiên Nhân suy kiếp. Khi Vương Lâm nhìn vào, hắn có cảm giác thần thức bị trận pháp hấp thu và cắn nuốt.","thuocTinh":"Truyền tống thần thức","dacDiem":"Phức tạp và tạo cảm giác hấp thu thần thức.","congNang":["Đưa thần thức Thiên Tôn xuất hiện trên đại lục lơ lửng trong Thiên Nhân suy kiếp @c1832"],"tabs":{"tienTrinh":[{"chuong":"@c1832","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm vào Thiên Nhân suy kiếp","text":"Vương Lâm xuất hiện tại trận pháp cổ xưa trên đại lục lơ lửng và nhận ra trận pháp rất phức tạp.","anchor":"Trận pháp này cực kỳ phức tạp"}]},"capNhatToi":"@c1832","nguon":["@c1832"]},{"id":"dung-nhap-than-thong-khi-xong-tang-thien-nhan-suy-kiep","name":"Dung nhập thần thông khi xông tầng Thiên Nhân suy kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cơ chế thần thông","phamCap":"Không rõ","hePhai":"Thiên Nhân suy kiếp","soHuu":[],"blurb":"Cơ chế đo chiến lực khi Thiên Tôn xông các tầng trong Thiên Nhân suy kiếp, dựa vào số đạo thần thông được dung nhập.","detail":"Theo lời bàn của các Thiên Tôn, để xông qua tầng bảy cần dung nhập tối thiểu sáu mươi ba đạo thần thông. Tầng chín là ngưỡng khiến Đại Thiên Tôn coi trọng và người vượt qua được xem là rất gần với Dược Thiên Tôn.","thuocTinh":"Đo chiến lực qua thần thông dung nhập","dacDiem":"Số đạo thần thông dung nhập liên hệ trực tiếp với tầng có thể vượt qua.","congNang":["Làm thước đo khả năng xông tầng của Thiên Tôn trong Thiên Nhân suy kiếp @c1832"],"tabs":{"tienTrinh":[{"chuong":"@c1832","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lời bàn quanh tầng bảy","text":"Các Thiên Tôn nói rằng muốn vượt tầng bảy cần dung nhập tối thiểu sáu mươi ba đạo thần thông.","anchor":"Có thể xông qua tầng bảy, tối thiều phải dung nhập được sáu mươi ba đạo thần thông"}]},"capNhatToi":"@c1832","nguon":["@c1832"]},{"id":"ho-phong-hoan-vu-thuat","name":"Hô Phong Hoán Vũ thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông được Vương Lâm dung hợp nhiều lần vào một quyền khi xông tầng một Thiên Tôn Niết.","detail":"Ở lần vượt lại tầng một Thiên Tôn Niết, Vương Lâm dung hợp chín lần Hô Phong Hoán Vũ thuật vào một quyền đánh vào hư vô, tạo thành chín hắc long và khiến chín tu chân tinh đồng thời sụp đổ. Cách thi triển này đáp ứng yêu cầu phải một chiêu hủy diệt toàn bộ mục tiêu cùng lúc.","nguon":["@c1833"]},{"id":"mot-chi-bay-muoi-dao-than-thong-cua-hai-tu","name":"Một chỉ bảy mươi đạo thần thông của Hải Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Thần thông Hải Tử Thiên Tôn thi triển khi chặn Vương Lâm lấy thụ linh Sơn Hải.","detail":"Hải Tử Thiên Tôn điểm một chỉ khiến thiên địa biến sắc, nước biển giữa nàng và Vương Lâm hiện bảy mươi dòng xoáy, mỗi dòng xoáy ẩn chứa một đạo thần thông của nàng.","uyLuc":"Tạo bảy mươi dòng xoáy thần thông để một thức đánh lui đối thủ.","congNang":["Một chỉ hóa ra bảy mươi dòng xoáy, mỗi dòng xoáy ẩn chứa một đạo thần thông của Hải Tử Thiên Tôn @c1834"],"nguon":["@c1834"],"tabs":{"tienTrinh":[{"chuong":"@c1834","loai":"thi triển","importance":"normal","giaiDoan":"Chặn Vương Lâm","text":"Hải Tử Thiên Tôn dùng thuật cực mạnh tạo bảy mươi dòng xoáy thần thông để đánh lui Vương Lâm.","anchor":"trong mỗi dòng xoáy lại ẩn chứa một đạo thần thông của nàng"}]},"capNhatToi":"@c1834"},{"id":"loi-dinh-ban-nguyen-chan-than","name":"Lôi đình bản nguyên chân thân","cn":"","aliases":[],"loai":"khac","loaiLabel":"Chân thân bản nguyên","phamCap":"khong-ro","hePhai":"Lôi đình bản nguyên","soHuu":["Vương Lâm"],"blurb":"Chân thân bản nguyên lôi đình của Vương Lâm, được gọi ra để thay bản thể mạo hiểm tiếp cận mảnh Tiên Cực Kiếm trong phong ấn Sơn Hải Thụ. Khi chụp được mảnh kiếm, chân thân này khiến phong ấn nơi Sơn Hải Thụ bộc phát.","detail":"Vương Lâm nhận ra phong ấn Sơn Hải Thụ do Tiên Tổ bố trí có thể bị dẫn động nên không để bản thể trực tiếp tiến tới. Hắn gọi lôi đình bản nguyên chân thân biến ảo ra, lao thẳng tới mảnh vỡ Tiên Cực Kiếm và chụp lấy nó trong phong ấn.","congNang":["Thay bản thể tiến vào nơi nguy hiểm để đoạt vật trong phong ấn @c1835"],"thuocTinh":"Lôi đình bản nguyên","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1835","tangDatToi":"có thể biến ảo ra độc lập để hành động","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1835","loai":"thi triển","importance":"normal","giaiDoan":"Đoạt mảnh Tiên Cực Kiếm","text":"Vương Lâm gọi lôi đình bản nguyên chân thân lao tới chụp mảnh vỡ Tiên Cực Kiếm trong Sơn Hải Thụ.","anchor":"thân thể không đi tới mà nhoáng lên, lôi đình bản nguyên chân thân biến ảo ra, tiến thẳng về phía mảnh vỡ của Tiên Cực Kiếm"}]},"capNhatToi":"@c1835","nguon":["@c1835"]},{"id":"son-hai-tran","name":"Sơn Hải trận","cn":"","aliases":["Trận pháp mực đen của Hải Tử Thiên Tôn"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Sơn Hải","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Trận pháp do Hải Tử Thiên Tôn Nghệ Đình triển khai trong Sơn Hải, khiến nước biển hóa đen để phong tỏa đường rời đi của Vương Lâm.","detail":"Khi Hải Tử Thiên Tôn tuyên bố Sơn Hải là đan phủ của mình, nàng mở Sơn Hải trận, làm nước biển tám hướng gần như hóa thành màu đen và biến hơn phân nửa mặt biển thành một màn mực kiên cố.","congNang":["Phong tỏa Sơn Hải bằng nước biển hóa đen @c1837"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1837","tangDatToi":"thi triển được Sơn Hải trận","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1837","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong tỏa Sơn Hải","text":"Hải Tử Thiên Tôn triển khai Sơn Hải trận, khiến nước biển tám hướng hóa đen để ngăn Vương Lâm rời khỏi Sơn Hải.","anchor":"Lời nói của nàng truyền ra, chỉ thấy nước biển tám hướng hầu như toàn bộ hóa thành màu đen"}]},"capNhatToi":"@c1837","nguon":["@c1837"]},{"id":"chuong-gio-lam-va-chim-lam-bay-muoi-dao-than-thong","name":"Chuông gió lam và chim lam bảy mươi đạo thần thông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hải Tử Thiên Tôn","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Thần thông Hải Tử Thiên Tôn thi triển khi đối kháng Dịch Linh Ấn của Vương Lâm, dùng lam quang hóa chuông gió rồi hiện ra chim lam chứa bảy mươi đạo thần thông.","detail":"Hải Tử Thiên Tôn vung tay, lam quang hóa thành chuông gió lớn, từ trong chuông hiện ra chim màu lam đập cánh bảy mươi lần, mỗi lần như ẩn chứa một đạo thần thông để đánh vào Dịch Linh Ấn.","congNang":["Tạo chim lam chứa bảy mươi đạo thần thông để đối kháng công kích @c1837"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1837","tangDatToi":"thi triển được bảy mươi đạo thần thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1837","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Dịch Linh Ấn","text":"Hải Tử Thiên Tôn dùng chuông gió lam gọi ra chim lam, lấy bảy mươi đạo thần thông đánh vào Dịch Linh Ấn của Vương Lâm.","anchor":"Chỉ thấy một con chim màu lam từ bên trong đó biến ảo ra"}]},"capNhatToi":"@c1837","nguon":["@c1837"]},{"id":"menh-do-than-ra-la-de-nhat-dao","name":"Mệnh do thân ra là đệ nhất đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hải Tử Thiên Tôn","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Đạo thần thông thứ nhất trong chuỗi ấn ký hình trứng của Hải Tử Thiên Tôn, ban đầu hợp thành bảy mươi nét bút tương ứng bảy mươi đạo thần thông.","detail":"Hải Tử Thiên Tôn điểm tay trước người, tạo ra ấn ký hình trứng do bảy mươi nét bút hợp thành, trong đó ẩn chứa bảy mươi đạo thần thông.","congNang":["Tạo ấn ký hình trứng gồm bảy mươi nét bút, ẩn chứa bảy mươi đạo thần thông @c1837"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1837","tangDatToi":"đệ nhất đạo","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1837","loai":"thi triển","importance":"normal","giaiDoan":"Đệ nhất đạo","text":"Hải Tử Thiên Tôn thi triển Mệnh do thân ra, tạo ấn ký hình trứng trước người để tiếp tục áp chế Vương Lâm.","anchor":"Ngọc thủ của Hải Tử Thiên Tôn điểm ra, bất ngờ khiến trước người nàng xuất hiện một ấn kỳ hình trứng"}]},"capNhatToi":"@c1837","nguon":["@c1837"]},{"id":"thuong-thien-bat-nghich-de-nhi-dao","name":"Thương thiên bất nghịch đệ nhị đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hải Tử Thiên Tôn","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Đạo thần thông thứ hai Hải Tử Thiên Tôn gắng sức thi triển, khiến ấn ký hình trứng tăng lên chín mươi sáu nét bút.","detail":"Sau Mệnh do thân ra, Hải Tử Thiên Tôn tiếp tục thi triển Thương thiên bất nghịch, làm ấn ký hình trứng từ bảy mươi nét bút tăng lên chín mươi sáu nét, tương đương chín mươi sáu đạo thần thông dung hợp.","congNang":["Nâng ấn ký hình trứng lên chín mươi sáu nét bút, tương đương chín mươi sáu đạo thần thông dung hợp @c1837"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1837","tangDatToi":"đệ nhị đạo","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1837","loai":"thi triển","importance":"normal","giaiDoan":"Đệ nhị đạo","text":"Hải Tử Thiên Tôn thi triển Thương thiên bất nghịch, tăng uy lực ấn ký hình trứng lên chín mươi sáu đạo thần thông dung hợp.","anchor":"Vốn bảy mươi nét bút lúc này trong nháy mắt hóa thành chín mươi sáu nét"}]},"capNhatToi":"@c1837","nguon":["@c1837"]},{"id":"an-ky-hinh-trung-cua-hai-tu-thien-ton","name":"Ấn ký hình trứng của Hải Tử Thiên Tôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sư truyền của Hải Tử Thiên Tôn","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Thần thông Hải Tử Thiên Tôn dùng máu ngưng tụ, có thể chứa nhiều đạo thần thông để công kích đối thủ.","detail":"Trong trận chiến ở biển Sơn Hải, Hải Tử Thiên Tôn phun máu ngưng tụ ấn ký hình trứng chứa chín mươi sáu đạo thần thông để đánh Vương Lâm. Về sau nàng gắng thi triển phiên bản chứa chín mươi đạo thần thông để phối hợp công kích bàn tay phong ấn.","nguon":["@c1838"],"dinhDanh":"goc","thuocTinh":"Thần thông ngưng tụ bằng máu","nguonGoc":"Do sư tôn của Hải Tử Thiên Tôn truyền thụ","uyLuc":"Có thể chứa chín mươi sáu đạo thần thông quỷ dị khó lường.","dacDiem":"Ấn ký hình trứng, khi cần có thể giảm số đạo thần thông để phối hợp công kích.","congNang":["Ngưng tụ nhiều đạo thần thông vào một ấn ký để công kích đối thủ @c1838"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1838","tangDatToi":"Chín mươi sáu đạo thần thông","trangThai":"dang-tu"}],"capNhatToi":"@c1838","tabs":{"tienTrinh":[{"chuong":"@c1838","loai":"thi triển","importance":"normal","giaiDoan":"Chín mươi sáu đạo thần thông","text":"Hải Tử Thiên Tôn phun máu ngưng tụ ấn ký hình trứng chứa chín mươi sáu đạo thần thông để công kích Vương Lâm, rồi về sau dùng bản chín mươi đạo phối hợp đánh bàn tay phong ấn.","anchor":"ngưng tụ ấn ký hình trứng ẩn chứa chín mươi sáu đạo thần thông quỷ dị khó lường"}]}},{"id":"nam-than-mach-trong-than-the-vuong-lam","name":"Năm thần mạch trong thân thể Vương Lâm","cn":"","loai":"khac","loaiLabel":"Thần mạch","phamCap":"Không rõ","hePhai":"Thân thể Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Năm thần mạch trong thân thể Vương Lâm là nền tảng vận chuyển sức mạnh giúp hắn bộc phát tốc độ trong hiểm cảnh.","detail":"Khi bàn tay phong ấn sắp chạm tới Hải Tử Thiên Tôn, Vương Lâm vận chuyển năm thần mạch ầm ầm, phối hợp Tốc Thần Quyết để ngưng tụ thêm tàn ảnh thứ chín mươi tám.","nguon":["@c1838"],"dinhDanh":"goc","thuocTinh":"Thần mạch trong thân thể","uyLuc":"Hỗ trợ bộc phát tốc độ đến mức ngưng thêm tàn ảnh của Tốc Thần Quyết.","congNang":["Tăng tốc độ vận chuyển và bộc phát của Vương Lâm khi thi triển Tốc Thần Quyết @c1838"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1838","tangDatToi":"Năm thần mạch vận chuyển đồng thời","trangThai":"dang-tu"}],"capNhatToi":"@c1838","tabs":{"tienTrinh":[{"chuong":"@c1838","loai":"thi triển","importance":"normal","giaiDoan":"Bộc phát tốc độ","text":"Vương Lâm vận chuyển năm thần mạch để đẩy tốc độ lên cao, hỗ trợ Tốc Thần Quyết ngưng ra tàn ảnh thứ chín mươi tám.","anchor":"năm thần mạch trong thân thể ầm ầm vận chuyển, bằng tốc độ cực nhanh điên cuồng xoay tròn"}]}},{"id":"phong-an-son-hai-thu","name":"Phong ấn Sơn Hải Thụ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Phong ấn / trận pháp","phamCap":"không rõ","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ"],"blurb":"Phong ấn do Tiên Tổ bố trí tại Sơn Hải Thụ, biểu hiện qua bàn tay gãy và thân ảnh mơ hồ ngoài tầng sáng. Nó có thể nuốt phòng hộ, cô lập liên hệ bên ngoài và phong ấn sinh linh không thuộc Tiên Cương.","detail":"Trong chương 1839, Vương Lâm nhận định bàn tay gãy đang nuốt tầng sáng là phong ấn Sơn Hải Thụ. Hải Tử Thiên Tôn nói phong ấn này năm xưa do Tiên Tổ bố trí; cơ chế của nó bao trùm tầng phòng hộ, cắt liên hệ bên ngoài, ép không gian tối đen và xuất hiện thân ảnh mơ hồ tuyên bố phong ấn sinh linh không thuộc Tiên Cương.","dinhDanh":"goc","thuocTinh":"phong ấn, trận pháp","nguonGoc":"Do Tiên Tổ bố trí tại Sơn Hải Thụ.","uyLuc":"Có thể nuốt tầng phòng hộ của Hải Tử Thiên Tôn, cô lập hai Thiên Tôn khỏi ngoại giới và làm xuất hiện thân ảnh thực thi phong ấn.","dacDiem":"Biểu hiện bằng bàn tay gãy hóa lớn và hư vô đen ngoài tầng sáng.","congNang":["Cô lập liên hệ giữa tầng sáng với bên ngoài @c1839","Phong ấn sinh linh bị nhận định không thuộc Tiên Cương @c1839"],"trangThai":"đang vận hành","capNhatToi":"@c1839","tabs":{"tienTrinh":[{"chuong":"@c1839","loai":"xuất hiện","importance":"normal","giaiDoan":"Bàn tay gãy nuốt tầng sáng","text":"Phong ấn Sơn Hải Thụ lộ rõ qua bàn tay gãy nuốt tầng phòng hộ, cô lập liên hệ với bên ngoài và hiện ra thân ảnh mơ hồ tuyên bố phong ấn sinh linh không thuộc Tiên Cương.","anchor":"Phong ấn này năm đó là do Tiên Tổ bố trí"}]},"nguon":["@c1839"]},{"id":"moc-ban-nguyen","name":"Mộc bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"không rõ","hePhai":"Ngũ hành bản nguyên","soHuu":["Vương Lâm"],"blurb":"Mộc bản nguyên hình thành bên trong hệ ngũ hành bản nguyên của Vương Lâm sau khi hắn dung hợp hai khối Sơn Hải thụ linh trong lúc bị phong vây. Tính tới mốc ghi nhận, nó đang trong giai đoạn trưởng thành nhanh chóng, chưa bộc lộ đầy đủ uy lực chiến đấu.","detail":"Trong khoảng thời gian bị nhốt bên trong tầng sáng phòng hộ, Vương Lâm tiến hành dung hợp hai khối Sơn Hải thụ linh. Quá trình này thúc đẩy sự xuất hiện của mộc bản nguyên — thuộc tính mộc trước đó còn thiếu — bổ khuyết vào hệ ngũ hành bản nguyên của hắn. Sự kiện đánh dấu bước tiến mới trên tuyến tu luyện bản nguyên ngũ hành, mở rộng nền tảng sức mạnh tổng thể. Tại thời điểm ghi nhận, mộc bản nguyên đang trưởng thành nhanh chóng nhưng chưa được vận dụng trong thực chiến.","dinhDanh":"goc","thuocTinh":"mộc, bản nguyên","nguonGoc":"Hình thành nhờ Vương Lâm dung hợp Sơn Hải thụ linh trong lúc bị phong vây.","uyLuc":"Đang trưởng thành, chưa bộc lộ đầy đủ uy lực chiến đấu trong chương ghi nhận.","dacDiem":"Sinh ra bên trong hệ ngũ hành bản nguyên của Vương Lâm, hình thành trực tiếp từ việc dung hợp Sơn Hải thụ linh.","congNang":["Bổ sung thuộc tính mộc vào ngũ hành bản nguyên của Vương Lâm @c1839"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1839","tangDatToi":"mới hình thành","trangThai":"đang tu"}],"trangThai":"đang trưởng thành","capNhatToi":"@c1839","tabs":{"tienTrinh":[{"chuong":"@c1839","loai":"xuất hiện","importance":"major","giaiDoan":"Mới hình thành","text":"Mộc bản nguyên hình thành trong ngũ hành bản nguyên của Vương Lâm sau khi hắn dung hợp hai khối Sơn Hải thụ linh.","anchor":"có thêm một mộc bản nguyên, đang nhanh chóng trưởng thành"}]},"nguon":["@c1839"]},{"id":"than-thong-mi-hoac-cua-hai-tu-thien-ton","name":"Thần thông mị hoặc của Hải Tử Thiên Tôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hải Tử Thiên Tôn","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Thần thông mị hoặc được Hải Tử Thiên Tôn bộc lộ trong lúc nói chuyện với Vương Lâm về song tu đạo lữ. Vương Lâm nhận ra và lạnh giọng yêu cầu nàng thu lại.","detail":"Trong tầng sáng, Hải Tử Thiên Tôn chuyển giọng điệu sang mị hoặc khi nói có thể giúp Vương Lâm tìm đạo lữ song tu. Vương Lâm lập tức nhìn ra trạng thái này, yêu cầu nàng thu thần thông và gọi lôi đình chân thân ra ngăn cách.","thuocTinh":"mị hoặc","uyLuc":"Có thể tác động qua đối thoại và thần thái, nhưng bị Vương Lâm nhận ra ngay.","dacDiem":"Gắn với biểu hiện khác thường của Hải Tử Thiên Tôn trong thời gian bị nhốt trong tầng sáng.","congNang":["Mị hoặc đối phương trong lúc trò chuyện, khiến không khí đối thoại chuyển sang hướng song tu đạo lữ @c1840"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1840","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1840","loai":"thi triển","importance":"normal","giaiDoan":"bộc lộ trong tầng sáng","text":"Hải Tử Thiên Tôn dùng sắc thái mị hoặc khi nói chuyện song tu đạo lữ, khiến Vương Lâm nhận ra và yêu cầu nàng thu thần thông.","anchor":"Thu lại thần thông mị hoặc của ngươi đi."}]},"capNhatToi":"@c1840","nguon":["@c1840"]},{"id":"tang-sang-trong-phong-an-son-hai-thu","name":"Tầng sáng trong phong ấn Sơn Hải Thụ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kết giới/phòng hộ","phamCap":"","hePhai":"","soHuu":[],"blurb":"Tầng sáng bảo hộ bên trong phong ấn Sơn Hải Thụ, che chở Vương Lâm và Hải Tử Thiên Tôn trước thân ảnh do bàn tay gầy huyễn hóa.","detail":"Trong chương này, tầng sáng liên tục bị thân ảnh ngoài tầng sáng công kích và co hẹp: ban đầu từ năm mươi trượng xuống ba mươi trượng, sau ba năm còn ba trượng, rồi tiếp tục bị ép xuống hai trượng, một trượng và cuối cùng chỉ còn nửa trượng. Sự co hẹp của tầng sáng khiến không gian bảo hộ của Vương Lâm và Hải Tử Thiên Tôn ngày càng nguy cấp.","nguon":["@c1841"]},{"id":"mot-chi-cua-cuu-de","name":"Một chỉ của Cửu Đế","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại Thiên Tôn","hePhai":"Tiên Tộc","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Thần thông một chỉ được Cửu Đế thi triển từ bầu trời Sơn Hải để cứu Hải Tử Thiên Tôn.","detail":"Cửu Đế điểm một chỉ xuống biển, khiến nước biển sôi trào, quay cuồng và hóa thành một chỉ đánh vào bàn tay khổng lồ đang chụp Hải Tử Thiên Tôn, cắt thế truy kích của dị vật phong ấn.","congNang":["Chặn bàn tay gãy đang truy kích Hải Tử Thiên Tôn @c1842"],"uyLuc":"Có thể hóa nước biển Sơn Hải thành chỉ lực va chạm với bàn tay gãy.","dacDiem":"Do Cửu Đế Đại Thiên Tôn thi triển bằng một động tác điểm chỉ.","nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1842","tangDatToi":"Thi triển cứu người","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1842","loai":"thi triển","importance":"normal","giaiDoan":"Cứu Hải Tử","text":"Cửu Đế điểm một chỉ xuống biển, khiến nước biển hóa thành chỉ lực đánh vào bàn tay khổng lồ đang truy kích Hải Tử Thiên Tôn.","anchor":"nước biển như sôi trào, không ngừng quay cuồng chấn động, bất ngờ hóa thành một chỉ"}]},"dinhDanh":"goc","capNhatToi":"@c1842","nguon":["@c1842"]},{"id":"than-thong-dung-hop-than-the","name":"Thần thông dung hợp thân thể","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chiến lực Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dung hợp thân thể là chiêu thức chiến đấu cho phép Vương Lâm dung hợp nhiều đạo thần thông vào một quyền hoặc một chỉ. Sau khi luyện hóa mảnh vỡ Tiên Cực Kiếm, số đạo thần thông có thể dung hợp đạt mười ba, là cực hạn hiện tại của hắn.","detail":"Thần thông dung hợp thân thể là phương thức chiến đấu trực tiếp, tập trung uy lực nhiều đạo thần thông vào đòn đánh vật lý duy nhất của thân thể. Ban đầu Vương Lâm dung hợp được chín đạo thần thông trong mỗi đòn, nhưng sau khi hấp thu và luyện hóa mảnh vỡ Tiên Cực Kiếm sinh ra kim bản nguyên, mức dung hợp tăng lên mười ba đạo. Khi kiểm nghiệm lại sức mạnh, hắn xác nhận đây là giới hạn hiện tại, đồng thời ghi nhận rằng phối hợp bản nguyên chân thân có thể tiếp tục nâng cao con số này.","thuocTinh":"dung hợp thần thông","uyLuc":"Một quyền một chỉ đạt tới mười ba đạo thần thông khi Vương Lâm kiểm nghiệm sau khi sinh kim bản nguyên.","dacDiem":"Có thể tăng thêm khi phối hợp bản nguyên chân thân.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1843","tangDatToi":"một quyền một chỉ dung hợp mười ba đạo","trangThai":"đang tu"}],"congNang":["Dung hợp nhiều đạo thần thông vào đòn đánh trực tiếp của thân thể (một quyền hoặc một chỉ) @c1843"],"tabs":{"tienTrinh":[{"chuong":"@c1843","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"mười ba đạo","text":"Vương Lâm tăng mức dung hợp thần thông trong một quyền một chỉ lên mười ba đạo sau khi luyện hóa mảnh vỡ Tiên Cực Kiếm.","anchor":"Mười ba đạo thần thông, nếu triển khai bản nguyên chân thân thì dưới sự gia tăng"}]},"capNhatToi":"@c1843","nguon":["@c1843"]},{"id":"ban-nguyen-chan-than","name":"Bản nguyên chân thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên chiến lực","phamCap":"Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hình thái chiến lực do bản nguyên ngưng tụ, có thể tăng phúc thần thông khi chiến đấu.","detail":"Vương Lâm tính toán rằng khi bản nguyên chân thân xuất hiện, số thần thông đánh ra sẽ tăng gấp bội, giúp hắn đủ giao chiến với Thiên Tôn dung hợp năm mươi hai đạo thần thông.","thuocTinh":"bản nguyên","uyLuc":"Tăng gấp bội chiến lực khi phối hợp thần thông dung hợp thân thể.","dacDiem":"Gắn với ngũ hành chân thân, lôi đình chân thân và hư bản nguyên trong suy tính chiến lực của Vương Lâm.","congNang":["Tăng phúc số đạo thần thông khi bản nguyên chân thân xuất hiện @c1843"],"tabs":{"tienTrinh":[{"chuong":"@c1843","loai":"nhắc tới","importance":"normal","giaiDoan":"tăng phúc chiến lực","text":"Vương Lâm dùng bản nguyên chân thân làm cơ sở tính toán khả năng giao chiến với Thiên Tôn năm mươi hai đạo thần thông.","anchor":"Nếu triển khai bản nguyên chân thân thì sau khi bản nguyên chân thân xuất hiện"}]},"capNhatToi":"@c1843","nguon":["@c1843"]},{"id":"di-tuong-bien-may-troi-va-tien-cung-cua-luu-kim-buu","name":"Dị tượng biến mây trời và tiên cung của Lưu Kim Bưu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/ảo thuật","phamCap":"Không rõ","hePhai":"Lưu Kim Bưu","soHuu":["Lưu Kim Bưu"],"blurb":"Thủ đoạn tạo dị tượng của Lưu Kim Bưu dùng để lừa phàm nhân Đại Thánh Châu. Hắn khiến mây trời biến đổi, hiện tiên cung và tiên hạc để dựng vẻ tiên gia.","detail":"Lưu Kim Bưu vung tay khiến bầu trời từ nhiều mây hóa thành ngàn dặm không mây, rồi tiếp tục biến ảo ra tiên cung xa hoa và tiên hạc. Màn thi triển làm phàm nhân kinh sợ, nhưng chính hắn cũng vã mồ hôi vì gánh nặng của thủ đoạn này.","thuocTinh":"Ảo thuật tạo dị tượng","uyLuc":"Có thể làm đám phàm nhân tin là cảnh tiên gia hiện thế.","dacDiem":"Dùng để phô trương và lừa gạt hơn là chiến đấu trực diện.","congNang":["Tạo cảnh trời quang, tiên cung và tiên hạc để mê hoặc phàm nhân @c1844"],"nguoiTu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1844","tangDatToi":"Thi triển trước phàm nhân","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1844","loai":"thi triển","importance":"normal","giaiDoan":"Lừa phàm nhân Đại Thánh Châu","text":"Lưu Kim Bưu thi triển dị tượng mây trời, tiên cung và tiên hạc để khiến phàm nhân tin mình là đại tiên.","anchor":"Lập tức bầu trời màu xanh lam lập tức có một tòa cung điện cực kỳ xa hoa bất ngờ biến ảo ra."}]},"capNhatToi":"@c1844","nguon":["@c1844"]},{"id":"thu-doan-giau-troi-vuot-bien-tu-chat","name":"Thủ đoạn giấu trời vượt biển tư chất","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lưu Kim Bưu"],"blurb":"Thủ đoạn do Lưu Kim Bưu dùng để làm tư chất của trẻ được chọn trông ưu tú hơn khi khảo hạch nhập Đại Thánh Tông. Bản chất là ngụy trang tư chất, có nguy cơ bị phát hiện về sau.","detail":"Lưu Kim Bưu nói với năm đứa trẻ rằng tư chất thật của chúng khó được Đại Thánh Tông thu nhận, nhưng hắn có phương pháp khiến tư chất trông như được giấu trời vượt biển. Hắn chia mức giả tư chất thành ưu việt, thượng giai và tầm thường, đồng thời khuyên chọn tầm thường để giảm nguy cơ bị dò xét lại sau nhập môn.","thuocTinh":"Ngụy trang tư chất khảo hạch","uyLuc":"Có thể khiến người được chọn vượt qua đánh giá tư chất ban đầu của tu sĩ khảo hạch.","dacDiem":"Hiệu quả là giả, nếu biểu hiện về sau không tương xứng và bị kiểm tra lại thì có thể bị phát hiện.","congNang":["Ngụy trang tư chất của trẻ phàm nhân để tăng khả năng được Đại Thánh Tông nhận vào khảo hạch nhập môn @c1845"],"nguoiTu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1845","tangDatToi":"Có thể thi triển để giả nhiều mức tư chất","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1845","loai":"xuất hiện","importance":"normal","giaiDoan":"Đề nghị giả tư chất","text":"Lưu Kim Bưu lần đầu nói rõ phương pháp giấu trời vượt biển tư chất với năm đứa trẻ và dùng nó làm nền cho giao dịch đưa chúng nhập Đại Thánh Tông.","anchor":"có một phương pháp có thể khiến cho tư chất của các ngươi có thể giống như giấu trời vượt biển"}]},"dinhDanh":"goc","capNhatToi":"@c1845","nguon":["@c1845"]},{"id":"thuat-tinh-toan-vi-tri-luu-kim-buu","name":"Thuật tính toán vị trí Lưu Kim Bưu","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật suy tính","phamCap":"Không rõ","hePhai":"Vân Môn","soHuu":["Lão già Vân Môn tính toán vị trí Lưu Kim Bưu"],"blurb":"Thuật suy tính được lão già Vân Môn dùng để truy ra vị trí Lưu Kim Bưu. Thuật này lấy đứa bé trai bị cải tư chất làm đầu mối, tạo gợn sóng thiên địa mà Vương Lâm phát hiện.","detail":"Trong đại điện Vân Môn, lão già đặt tay lên thiên linh đứa bé trai để tính toán biến hóa trong thiên địa, từ đó truy ra vị trí Lưu Kim Bưu. Kết quả suy tính được chuyển thành hành động truy bắt bằng ngọc giản dẫn đường.","thuocTinh":"Suy tính, truy tung","nguonGoc":"Vân Môn","congNang":["Truy vị trí mục tiêu thông qua đầu mối liên quan @c1846"],"nguoiTu":[{"ten":"Lão già Vân Môn tính toán vị trí Lưu Kim Bưu","tuChuong":"@c1846","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1846","loai":"thi triển","importance":"normal","giaiDoan":"Truy tìm Lưu Kim Bưu","text":"Lão già Vân Môn dùng đứa bé trai làm đầu mối để tính ra vị trí Lưu Kim Bưu, khiến thiên địa sinh ra gợn sóng bị Vương Lâm phát hiện.","anchor":"Đây là có người tính toán biến hóa trong thiên địa mà thành"}]},"capNhatToi":"@c1846","nguon":["@c1846"]},{"id":"phong-an-ky-uc-chuyen-the","name":"Phong ấn ký ức chuyển thế","cn":"","aliases":["Phong ấn trí nhớ kiếp trước","Phong ấn chuyển thế của Lưu Kim Bưu"],"loai":"bi-thuat","loaiLabel":"Phong ấn","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lưu Kim Bưu","Chu Dật"],"blurb":"Phong ấn nằm trong cơ thể Lưu Kim Bưu, khóa toàn bộ trí nhớ kiếp trước của hắn. Khi bị Vương Lâm kích thích bằng nỗi sợ khắc sâu trong linh hồn cùng cảm giác quen thuộc, phong ấn bắt đầu mơ hồ lỏng ra và có dấu hiệu tự phá.","detail":"Phong ấn chuyển thế tồn tại bên trong thân thể Lưu Kim Bưu, ngăn hắn nhớ lại ký ức kiếp trước. Sau khi cảnh giới đạo lừa gạt bước thứ hai của Lưu Kim Bưu sụp đổ trước Vương Lâm, nỗi sợ khắc sâu trong linh hồn cùng cảm giác quen thuộc với Vương Lâm đã kích thích phong ấn tới mức nó bắt đầu mơ hồ lỏng ra. Tuy nhiên, khác với Chu Dật, Lưu Kim Bưu không thể tự lực phá phong ấn; Vương Lâm phải trực tiếp điểm chỉ vào mi tâm hắn để kích phá.","thuocTinh":"phong ấn ký ức","congNang":["Phong ấn trí nhớ kiếp trước của Lưu Kim Bưu, khiến hắn không thể tự nhớ lại nếu không có ngoại lực phá phong ấn @c1848","Có thể tự lỏng ra khi bị nỗi sợ khắc sâu trong linh hồn và cảm giác quen thuộc kích thích mạnh @c1847","Cần ngoại lực trực tiếp kích phá nếu người mang phong ấn không đủ khả năng tự phá @c1848"],"dacDiem":"Bị nỗi sợ khắc sâu trong linh hồn và cảm giác quen thuộc với Vương Lâm kích thích tới mức mơ hồ lỏng ra.","nguoiTu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1847","tangDatToi":"bị phong ấn trong cơ thể","trangThai":"đang lỏng ra"}],"trangThai":"Được Vương Lâm phá cho Lưu Kim Bưu","capNhatToi":"@c1847","tabs":{"tienTrinh":[{"chuong":"@c1847","loai":"nhắc tới","importance":"major","giaiDoan":"Phong ấn lỏng ra","text":"Vương Lâm phát hiện phong ấn chuyển thế trong cơ thể Lưu Kim Bưu bị kích thích và có dấu hiệu tự phá.","anchor":"phong ấn chuyển thế trong cơ thể Lưu Kim Bưu lúc này đang mơ hồ lỏng ra"},{"chuong":"@c1848","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá trên Lưu Kim Bưu","text":"Vương Lâm nhận ra Lưu Kim Bưu không thể tự phá phong ấn giống Chu Dật, rồi điểm chỉ vào mi tâm hắn để kích phát ký ức hai đời.","anchor":"Xem ra hắn không thể tự mình phá vỡ phong ấn. Chu Dật không thể, hắn cũng không thể."}]},"nguon":["@c1847","@c1848"]},{"id":"ho-son-dai-tran-dong-lam-tong","name":"Hộ sơn đại trận Đông Lâm Tông","cn":"","loai":"than-thong","loaiLabel":"Trận pháp hộ sơn","phamCap":"Chưa rõ","hePhai":"Đông Lâm Tông","soHuu":["Đông Lâm Tông"],"blurb":"Trận pháp bảo vệ sơn môn Đông Lâm Tông. Khi Vương Lâm tới Đông Lâm Tông, trận này không ngăn được bước chân của hắn.","detail":"Hộ sơn đại trận là lớp phòng hộ của Đông Lâm Tông. Chương 1848 chỉ nêu trận pháp này tồn tại quanh sơn môn, nhưng trước Vương Lâm thì nó không tạo thành trở ngại.","thuocTinh":"Phòng hộ sơn môn","nguonGoc":"Đông Lâm Tông","uyLuc":"Có tác dụng bảo vệ sơn môn Đông Lâm Tông, nhưng không cản được Vương Lâm trong lần hắn tiến vào.","dacDiem":"Được nhắc trực tiếp khi Vương Lâm vượt vào Đông Lâm Tông.","trangThai":"Đang tồn tại","capNhatToi":"@c1848","congNang":["Bảo vệ sơn môn Đông Lâm Tông @c1848"],"tabs":{"tienTrinh":[{"chuong":"@c1848","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm vượt qua","text":"Hộ sơn đại trận Đông Lâm Tông được nhắc khi Vương Lâm đi vào tông môn, nhưng trận pháp không ngăn được hắn.","anchor":"Hộ sơn đại trận của Đông Lâm Tông không ngăn cản được bước chân của Vương Lâm."}]},"nguon":["@c1848"]},{"id":"mong-chuong-luan-hoi","name":"Mộng Chướng Luân Hồi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo cảm ngộ luân hồi","phamCap":"Hư bản nguyên, đạo thứ tư do Vương Lâm suy diễn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Mộng Chướng Luân Hồi là nhận thức do Vương Lâm minh ngộ tại Đông Lâm Tông sau khi đối chứng với đạo lừa gạt của Lưu Kim Bưu, hợp nhất ba hư bản nguyên sinh tử, nhân quả và chân giả thành luân hồi thiên địa. Đây được coi như đạo thứ tư của hư bản nguyên trong cảm ngộ của hắn.","detail":"Sau khi đối chứng với đạo lừa gạt của Lưu Kim Bưu tại Đông Lâm Tông, Vương Lâm diễn giải sinh tử thành sợi dây hai mặt nối vòng, nhân quả thành tấm lưới do vô số sinh tử hợp thành, chân giả thành mộng chướng bao phủ chúng sinh. Từ đó hắn lấy mộng chướng chúng sinh làm môi trường, dùng lưới nhân quả tạo thành luân hồi và bắt lấy chính bản thân mình trong đó, suy ra luân hồi thiên địa như đạo thứ tư của hư bản nguyên.","thuocTinh":"Luân hồi, sinh tử, nhân quả, chân giả, mộng chướng","nguonGoc":"Do Vương Lâm minh ngộ tại Đông Lâm Tông sau khi đối chứng với đạo lừa gạt của Lưu Kim Bưu","congNang":["Hợp nhất ba hư bản nguyên sinh tử, nhân quả và chân giả thành nhận thức luân hồi thiên địa @c1849","Dùng mộng chướng chúng sinh và lưới nhân quả để hình thành luân hồi trong cảm ngộ của Vương Lâm @c1849"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1849","tangDatToi":"Minh ngộ bước đầu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1849","loai":"xuất hiện","importance":"major","giaiDoan":"Xác lập đạo thứ tư","text":"Vương Lâm từ sinh tử, nhân quả và chân giả suy ra luân hồi thiên địa như đạo thứ tư của hư bản nguyên.","anchor":"Ta nối tiếp sinh tử lại, hình thành ra tấm lưới lớn nhân quả"}]},"capNhatToi":"@c1849","nguon":["@c1849"]},{"id":"sinh-tu-hu-ban-nguyen","name":"Sinh tử hư bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hư bản nguyên","phamCap":"Hư bản nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sinh tử hư bản nguyên được Vương Lâm diễn giải như sợi dây hai mặt sinh và tử, nối lại thành vòng tròn trong cảm ngộ luân hồi.","detail":"Trong minh ngộ tại Đông Lâm Tông, sinh tử không chỉ là ý cảnh cũ mà trở thành nền móng để Vương Lâm nối thành vòng và phát triển thành lưới nhân quả.","thuocTinh":"Sinh tử","dacDiem":"Sợi dây hai mặt sinh và tử, có thể nối thành vòng tròn trong cảm ngộ luân hồi","congNang":["Làm nền để Vương Lâm hình thành lưới nhân quả trong mộng chướng luân hồi @c1849"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1849","tangDatToi":"Diễn giải trong mộng chướng luân hồi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1849","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Diễn giải sinh tử","text":"Vương Lâm hiểu sinh tử như một sợi dây trói có hai mặt, nối lại thành vòng tròn để làm nền cho nhân quả.","anchor":"Ta hiểu được sinh tử, sinh tử đó là một sợi dây trói."}]},"capNhatToi":"@c1849","nguon":["@c1849"]},{"id":"nhan-qua-hu-ban-nguyen","name":"Nhân quả hư bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hư bản nguyên","phamCap":"Hư bản nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Nhân quả hư bản nguyên được Vương Lâm diễn giải như tấm lưới lớn do vô số sinh tử hợp thành.","detail":"Trong cảm ngộ ở Đông Lâm Tông, nhân quả là lưới giam chúng sinh bên trong, làm phần trung tâm để Vương Lâm tạo thành luân hồi trong mộng chướng.","thuocTinh":"Nhân quả","dacDiem":"Tấm lưới lớn do vô số sinh tử hợp thành","congNang":["Giam chúng sinh trong lưới nhân quả và được Vương Lâm dùng để tạo thành luân hồi trong mộng chướng @c1849"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1849","tangDatToi":"Diễn giải trong mộng chướng luân hồi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1849","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Diễn giải nhân quả","text":"Vương Lâm hiểu nhân quả như một tấm lưới lớn do sinh tử tạo thành, khiến chúng sinh khó giãy thoát.","anchor":"Ta hiểu được nhân quả, nhân quả giống như một tấm lưới"}]},"capNhatToi":"@c1849","nguon":["@c1849"]},{"id":"chan-gia-hu-ban-nguyen","name":"Chân giả hư bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hư bản nguyên","phamCap":"Hư bản nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chân giả hư bản nguyên được Vương Lâm diễn giải như mộng chướng tầng tầng trong lòng chúng sinh.","detail":"Trong cảm ngộ tại Đông Lâm Tông, chân giả là trạng thái khiến chúng sinh tưởng đã tỉnh nhưng vẫn có thể ở trong một tầng mộng khác, trở thành môi trường bao phủ luân hồi.","thuocTinh":"Chân giả, mộng chướng","dacDiem":"Mộng chướng tầng tầng, khiến ranh giới tỉnh và mộng khó phân biệt","congNang":["Bao phủ chúng sinh trong mộng chướng, làm môi trường để lưới nhân quả hình thành luân hồi @c1849"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1849","tangDatToi":"Diễn giải trong mộng chướng luân hồi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1849","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Diễn giải chân giả","text":"Vương Lâm hiểu chân giả như mộng chướng trong lòng mỗi người, tầng tầng bao phủ cảm nhận của chúng sinh.","anchor":"Ta cảm ngộ được chân giả, chân giả giống như mộng chướng."}]},"capNhatToi":"@c1849","nguon":["@c1849"]},{"id":"hu-ban-nguyen","name":"Hư bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hư bản nguyên giúp Vương Lâm nhận biết hư thực và nhìn thấu mộng chướng tử vong của Đông Lâm Tông.","detail":"Khi tới Đông Lâm Tông, Vương Lâm nhờ đã hiểu hư bản nguyên nên thấy được chân tướng tông môn đã chết, nhận ra mộng chướng tử vong và sinh cơ cô độc ở trung tâm, điều trước kia hắn không thể nhìn ra.","thuocTinh":"Hư thực","uyLuc":"Có thể giúp Vương Lâm nhìn thấu mộng chướng tử vong và nhận ra chân tướng bị huyễn cảnh che phủ.","dacDiem":"Gắn với khả năng phân biệt thật giả trong cảnh giới nhận thức của Vương Lâm.","congNang":["Nhìn thấu mộng chướng tử vong Đông Lâm Tông và phát hiện sinh cơ cô độc tại trung tâm @c1850"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1850","tangDatToi":"Đã hiểu ra hư bản nguyên của bản thân","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1850","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhìn thấu tử tông","text":"Hư bản nguyên giúp Vương Lâm nhìn ra chân tướng Đông Lâm Tông đã chết và mộng chướng đang che phủ nơi này.","anchor":"Trước khi Vương Lâm chưa hiểu ra hư bản nguyên của bản thân thì hắn dù có tới nơi đây nhưng cũng vẫn không thể nhìn ra như trước."}]},"capNhatToi":"@c1850","nguon":["@c1850"]},{"id":"mong-chuong-tu-vong-dong-lam-tong","name":"Mộng chướng tử vong Đông Lâm Tông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Mộng chướng","phamCap":"Không rõ","hePhai":"Đông Lâm Tông","soHuu":["Dược Thiên Tôn"],"blurb":"Mộng chướng tử vong Đông Lâm Tông là huyễn cảnh do vô số người chết và ký ức tông môn tạo thành. Nó khiến tử tông hiện ra như vẫn còn sinh cơ và có thể dung nhập người ngoài bước vào.","detail":"Sau khi nhìn thấu chân tướng, Vương Lâm nhận ra Đông Lâm Tông không phải quỷ hồn mà là mộng chướng tử vong. Người ngoài đi vào rất khó phát hiện sự thật, thậm chí bị cuốn vào huyễn cảnh giống như tông môn vẫn đang tồn tại.","thuocTinh":"Mộng chướng, tử khí, huyễn cảnh","nguonGoc":"Hình thành từ tử vong của Đông Lâm Tông và được sinh cơ cô độc của Dược Thiên Tôn duy trì bằng ký ức.","uyLuc":"Che phủ tử tông, khiến người ngoài khó nhận ra chân tướng và có thể bị dung nhập vào huyễn cảnh.","dacDiem":"Bề ngoài phồn hoa nhưng bản chất là tông môn đã chết, đầy hài cốt và tử khí.","congNang":["Che phủ cảnh tượng Đông Lâm Tông đã bị diệt, làm hiện ra tông môn phồn hoa trong mộng @c1850","Có thể khiến người ngoài đi vào bị dung nhập vào mộng chướng @c1850"],"tabs":{"tienTrinh":[{"chuong":"@c1850","loai":"xuất hiện","importance":"normal","giaiDoan":"Tử tông hiện hình","text":"Mộng chướng tử vong Đông Lâm Tông được Vương Lâm nhận ra là lớp huyễn cảnh khiến người chết như vẫn còn hoạt động và người ngoài khó phát hiện chân tướng.","anchor":"Trong mộng chướng này, người ngoài dù có tới nơi này cũng rất khó phát hiện ra, thậm chí bị hấp dẫn còn gặp phải ảo giác tương tự."}]},"capNhatToi":"@c1850","nguon":["@c1850"]},{"id":"thu-doan-muc-nat-hien-hien-dong-lam-tong","name":"Thủ đoạn mục nát-hiển hiện Đông Lâm Tông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đông Lâm Tông","soHuu":["Dược Thiên Tôn"],"blurb":"Thần thông được Dược Thiên Tôn dùng để hiển lộ hoặc che phủ chân tướng Đông Lâm Tông đã bị diệt. Khi thi triển, khí tức mục nát quét qua đại điện và toàn tông, khiến cảnh sinh cơ biến thành đất chết rồi có thể khôi phục như cũ.","detail":"Dược Thiên Tôn vung tay làm khí tức mục nát tràn ngập đại điện, lan ra Đông Lâm Tông, khiến lầu các mục nát, núi nước khô héo, đệ tử biến mất và hài cốt cùng bia đá máu hiện ra. Sau đó ông lại phất tay khiến chim ca hoa nở và cảnh môn nhân sinh hoạt trở về, cho thấy thuật này liên hệ trực tiếp với việc duy trì ảo cảnh sinh cơ trên nền tông môn đã chết.","congNang":["Hiển lộ chân tướng Đông Lâm Tông đã thành vùng đất chết @c1851","Che phủ lại cảnh mục nát bằng dáng vẻ sinh cơ và môn nhân sinh hoạt @c1851"],"nguoiTu":[{"ten":"Dược Thiên Tôn","tuChuong":"@c1851","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1851","loai":"thi triển","importance":"normal","giaiDoan":"Mở chân tướng Đông Lâm Tông","text":"Dược Thiên Tôn dùng thủ đoạn này để biến cảnh Đông Lâm Tông sinh cơ thành vùng đất chết, rồi lại khôi phục dáng vẻ bình thường trước mắt Vương Lâm và Lưu Kim Bưu.","anchor":"Chỉ thấy một luồng khí tức mục nát lập tức tràn ngập đại điện này."}]},"dinhDanh":"goc","capNhatToi":"@c1851","nguon":["@c1851"]},{"id":"mong-dao-thuat","name":"Mộng Đạo Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông được Vương Lâm dùng để nhập mộng truy xét quá khứ Đông Lâm Tông. Trong chương này nó dung hợp với Lưu Nguyệt và cần mượn lực lượng Quỷ Phàm.","detail":"Mộng Đạo Thuật giúp Vương Lâm chìm vào trạng thái kỳ dị, từ hiện tại bên Đông Lâm Trì mộng về biến cố trăm ngàn năm trước của Đông Lâm Tông. Khi dung hợp Lưu Nguyệt và có Quỷ Phàm hỗ trợ, thần thông này cho phép hắn quan sát cảnh Đông Lâm Tông quá khứ an bình rồi bị hủy diệt.","thuocTinh":"mộng, truy quá khứ","uyLuc":"Có thể mượn mộng cảnh để nhìn lại biến cố quá khứ của Đông Lâm Tông.","dacDiem":"Trong lần này cần dung hợp Lưu Nguyệt và mượn lực lượng Quỷ Phàm.","congNang":["Giúp Vương Lâm mộng về quá khứ Đông Lâm Tông @c1852"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1852","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1852","loai":"thi triển","importance":"normal","giaiDoan":"Dung hợp Lưu Nguyệt","text":"Vương Lâm thi triển Mộng Đạo Thuật, dung hợp với Lưu Nguyệt và mượn Quỷ Phàm để truy ngược biến cố Đông Lâm Tông trong mộng.","anchor":"Mộng Đạo Thuật của Vương Lâm dung hợp với thần thông Lưu Nguyệt"}]},"capNhatToi":"@c1852","nguon":["@c1852"]},{"id":"mong-dao-dung-hop-luu-nguyet","name":"Mộng Đạo dung hợp Lưu Nguyệt","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tổ hợp thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tổ hợp thần thông giữa Mộng Đạo Thuật và Lưu Nguyệt. Vương Lâm dùng nó cùng lực lượng Quỷ Phàm để trở lại quá khứ trong mộng.","detail":"Tổ hợp này lấy Mộng Đạo làm nền, dung hợp thần thông Lưu Nguyệt để nghịch chuyển năm tháng trong mộng. Vương Lâm phải mượn Quỷ Phàm của Đại Hồn Môn mới có thể nắm giữ thuật này trong lần truy xét biến cố Đông Lâm Tông.","thuocTinh":"mộng, thời gian","yeuCau":"Cần mượn lực lượng Quỷ Phàm.","uyLuc":"Cho phép người thi triển trở lại quá khứ trong mộng để quan sát biến cố xa xưa.","dacDiem":"Tổ hợp của hai thần thông, dùng cho truy xét biến cố Đông Lâm Tông.","congNang":["Mộng về biến cố trăm ngàn năm trước của Đông Lâm Tông @c1852"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1852","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1852","loai":"thi triển","importance":"normal","giaiDoan":"Truy quá khứ Đông Lâm","text":"Vương Lâm dùng Mộng Đạo dung hợp Lưu Nguyệt, mượn lực lượng Quỷ Phàm để mộng về biến cố Đông Lâm Tông trong quá khứ.","anchor":"Hắn có thể nắm giữ thuật này nhưng cần mượn lực lượng Quỷ Phàm"}]},"capNhatToi":"@c1852","nguon":["@c1852"]},{"id":"thai-so-ban-nguyen","name":"Thái sơ bản nguyên","aliases":["Thái Sơ bản nguyên","Thái sơ bản nguyên"],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lưu Kim Bưu","Vương Lâm"],"blurb":"Thái sơ bản nguyên là bản nguyên đặc thù xuất hiện dưới dạng luồng sáng trong Đông Lâm Trì, được Lưu Kim Bưu chạm vào và nhận biết tên gọi. Nó được xem là ban đầu của vạn vật, gắn với cơ duyên bản nguyên và lời tự thuật của Đồ mỗ về việc hành tẩu thương khung, nhìn vô số mặt trời biến hóa rồi minh ngộ.","detail":"Thái sơ bản nguyên tồn tại dưới dạng luồng sáng bên trong Đông Lâm Trì, nơi liên quan tới hồn phách tu sĩ thiên ngoại bị phong ấn dưới Đại Thánh Châu. Khi Lưu Kim Bưu chạm vào luồng sáng này, hắn nhận biết tên gọi của nó là Thái sơ bản nguyên. Trong lời tự thuật cuối chương, giọng Đồ mỗ kể từng hành tẩu thương khung, quan sát vô số mặt trời biến hóa rồi minh ngộ Thái sơ bản nguyên. Vương Lâm tiếp cận nó trong lần nhập trì thứ tư. Bản nguyên này được gọi là ban đầu của vạn vật, mang tính chất cơ duyên đặc thù dành cho người nhập Đông Lâm Trì cảm ngộ.","nguonGoc":"Luồng sáng trong Đông Lâm Trì, gắn với cơ duyên bản nguyên đặc thù và lời tự thuật của Đồ mỗ.","dacDiem":"Được gọi là ban đầu của vạn vật.","congNang":["Mang tính chất bản nguyên đặc thù để người nhập Đông Lâm Trì cảm ngộ @c1853"],"nguoiTu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1853","tangDatToi":"chạm vào luồng sáng và biết tên bản nguyên","trangThai":"đã tiếp xúc"},{"ten":"Vương Lâm","tuChuong":"@c1853","tangDatToi":"thấy luồng sáng càng gần trong lần nhập trì thứ tư","trangThai":"đang tiếp cận"}],"capNhatToi":"@c1853","tabs":{"tienTrinh":[{"chuong":"@c1853","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện trong Đông Lâm Trì","text":"Thái sơ bản nguyên lộ tên khi Lưu Kim Bưu chạm vào luồng sáng, rồi tiếp tục được nhắc trong lời tự thuật của Đồ mỗ vang lên trong tâm thần Vương Lâm.","anchor":"Đó là Thái sơ bản nguyên. Là ban đầu của vạn vật."}]},"nguon":["@c1853"]},{"id":"mac-diet-ban-nguyen","name":"Mặc Diệt bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên đặc thù","phamCap":"Bản nguyên đặc thù","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Mặc Diệt bản nguyên là bản nguyên đối ứng với Thái Sơ, đại biểu cho tất cả hắc ám và đêm tối khi mặt trời lặn. Vương Lâm bắt đầu cảm ngộ bản nguyên này qua mắt phải tại Đông Lâm Trì, tâm thần như chia làm hai nửa sáng-tối.","detail":"Sau khi minh ngộ Thái Sơ đại biểu mặt trời mọc, Vương Lâm suy ra còn tồn tại một loại bản nguyên đặc thù nắm giữ mặt trời lặn. Mắt phải hắn dần chuyển thành vùng đen tối, tâm thần phân thành hai cực: một bên là ánh sáng sau bình minh, một bên là đêm tối khi hoàng hôn buông xuống. Bản nguyên này được gọi là Mặc Diệt, xuất hiện như thực thể đối xứng hoàn toàn với Thái Sơ trong hệ thống bản nguyên mà Vương Lâm lĩnh ngộ.","thuocTinh":"Hắc ám, đêm tối, mặt trời lặn","trangThai":"Vương Lâm đang cảm ngộ","capNhatToi":"@c1854","congNang":["Đại biểu cho tất cả hắc ám và đêm tối khi mặt trời lặn @c1854"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1854","tangDatToi":"đang cảm ngộ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1854","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ rõ","text":"Mặc Diệt bản nguyên hiện ra như bản nguyên đối ứng với Thái Sơ, đại biểu hắc ám và được Vương Lâm bắt đầu cảm ngộ qua mắt phải.","anchor":"Mặc Diệt bản nguyên đại biểu cho tất cả hắc ám"}]},"dinhDanh":"goc","nguon":["@c1854"]},{"id":"hai-muoi-ba-dao-than-thong-dung-hop-mot-quyen","name":"Hai mươi ba đạo thần thông dung hợp một quyền","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông chiến đấu","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng khi thử cực hạn Không Kiếp trung kỳ tại Thiên Tôn Niết, dung hợp hai mươi ba đạo thần thông vào một quyền.","detail":"Khi xông tầng thứ năm Thiên Tôn Niết, Vương Lâm xác nhận hai mươi ba đạo thần thông là cực hạn hiện thời của bản thân nếu không mặc Hồn Khải. Một quyền dung hợp số thần thông này, phối hợp với ngũ hành chân thân, giúp hắn phá tầng năm.","nguon":["@c1856"]},{"id":"ba-dao-hu-bon-nguyen","name":"Ba đạo hư bổn nguyên","cn":"","aliases":["Ba đạo hư bản nguyên"],"loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ba đạo hư bổn nguyên được Vương Lâm vận dụng khi xông tầng chín Thiên Tôn Niết, phối hợp với các chân thân để tăng chiến lực.","detail":"Trong tầng thứ chín, Vương Lâm đồng thời dùng ngũ hành chân thân, lôi đình chân thân và ba đạo hư bổn nguyên. Sự phối hợp này khiến một quyền một chỉ của hắn đạt mức tương đương chín mươi hai đạo thần thông trong khảo nghiệm.","nguon":["@c1856"]},{"id":"cot-am-dao","name":"Cốt âm đao","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông đao ảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đao ảnh do Vương Lâm biến hóa từ tay phải ở tầng chín Thiên Tôn Niết, dùng để quét ngang tu chân tinh trong khảo nghiệm.","detail":"Khi xông tầng thứ chín, Vương Lâm biến ảo Cốt âm đao từ tay phải, chém ra chín mươi hai đao ảnh rồi dung hợp thành một đao. Một đao này quét ngang tinh không trong tầng khảo nghiệm và phá số lượng lớn tu chân tinh.","nguon":["@c1856"]},{"id":"cuc-thuy-dao","name":"Cực Thủy Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bát Cực Đạo","phamCap":"","hePhai":"Thái Cổ thần cảnh","soHuu":["Vương Lâm"],"blurb":"Một cực đạo thuộc Bát Cực Đạo, được Vương Lâm lĩnh ngộ sau khi vượt tầng mười hai Thiên Tôn Niết.","detail":"Sau khi Vương Lâm xông qua tầng thứ mười hai, quanh thân hắn xuất hiện hơi nước vô hình. Cửu Đế Đại Thiên Tôn nhận ra đó là Cực Thủy Đạo, đánh dấu Vương Lâm nắm thêm một cực đạo sau Cực Hỏa Đạo.","nguon":["@c1856"]},{"id":"mot-chi-cua-minh-dao-ton","name":"Một chỉ của Minh Đạo Tôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Minh Đạo Tôn","soHuu":["Minh Đạo Tôn"],"blurb":"Thần thông một chỉ Minh Đạo Tôn thi triển tại Thiên Tôn Niết để ép Vương Lâm rời Truyền Tống Trận. Một chỉ này hóa thành ngón tay khổng lồ, khiến Thiên Tôn Niết chấn động.","detail":"Minh Đạo Tôn điểm một chỉ trong Thiên Tôn Niết, dẫn động thiên địa lực hóa ra ngón tay khổng lồ đánh về Truyền Tống Trận. Mục đích là buộc Vương Lâm né tránh, phá thế rời đi của hắn, hoặc khiến thần thức hắn tổn hại khi truyền tống.","uyLuc":"Chấn động Thiên Tôn Niết và hóa thành ngón tay khổng lồ trong thiên địa.","congNang":["Công kích về phía Truyền Tống Trận để ép mục tiêu rời trận hoặc chịu rủi ro tổn hại thần thức @c1857"],"dinhDanh":"goc","nguoiTu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1857","tangDatToi":"thi triển một chỉ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1857","loai":"thi triển","importance":"normal","giaiDoan":"Ép Vương Lâm tại Truyền Tống Trận","text":"Minh Đạo Tôn điểm một chỉ hóa thành ngón tay khổng lồ đánh về Truyền Tống Trận, buộc Vương Lâm lao ra khỏi trận.","anchor":"Một chỉ này khiến Thiên Tôn Niết chấn động, một ngón tay khổng lồ biến ảo ra trong thiên địa"}]},"capNhatToi":"@c1857","nguon":["@c1857"]},{"id":"than-thong-hien-than-cua-tien-hoang","name":"Thần thông hiện thân của Tiên Hoàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông hiện thân","phamCap":"không rõ","hePhai":"Tiên Hoàng","soHuu":["Tiên Hoàng"],"blurb":"Thần thông đặc thù giúp Tiên Hoàng hiện thân cách không qua một tu sĩ Thiên Tôn tại Thiên Tôn Niết. Hắn dùng nó để hóa giải áp lực do Võ Phong Đại Thiên Tôn định ra tay.","detail":"Trong lúc Minh Đạo Tôn phá quy định ở Thiên Tôn Niết và Võ Phong định can thiệp, Tiên Hoàng dùng thần thông đặc thù xuất hiện tại nơi này thông qua một tu sĩ Thiên Tôn. Sự hiện thân ấy trực tiếp hóa giải áp lực của Võ Phong, cho phép xung đột tiếp tục.","uyLuc":"Có thể hiện thân cách không và ngăn áp lực Đại Thiên Tôn.","congNang":["Hiện thân qua một tu sĩ Thiên Tôn tại Thiên Tôn Niết @c1857","Hóa giải áp lực do Võ Phong Đại Thiên Tôn ra tay @c1857"],"dinhDanh":"goc","nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1857","tangDatToi":"thi triển hiện thân cách không","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1857","loai":"thi triển","importance":"normal","giaiDoan":"Ngăn Võ Phong tại Thiên Tôn Niết","text":"Tiên Hoàng dùng thần thông đặc thù hiện thân qua một tu sĩ Thiên Tôn và hóa giải áp lực của Võ Phong.","anchor":"Tiên Hoàng lúc này dùng thần thông đặc thù, xuất hiện ở nơi này!"}]},"capNhatToi":"@c1857","nguon":["@c1857"]},{"id":"phan-than-trong-phap-tac-cua-tien-cuong","name":"Phân thân trong pháp tắc của Tiên Cương","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Phân thân/pháp tắc","phamCap":"không rõ","hePhai":"Tiên Cương","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn phân thân pháp tắc được Vương Lâm dùng khi xông các tầng cao của Thiên Tôn Niết.","detail":"Khi thời gian Hồn Khải không còn nhiều, Vương Lâm dùng phân thân trong pháp tắc Tiên Cương, lấy hồn làm vật dẫn dung nhập vào thân thể để tăng khả năng vượt tầng.","thuocTinh":"pháp tắc Tiên Cương","congNang":["Dung nhập thân thể khi xông tầng Thiên Tôn Niết @c1859"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1859","tangDatToi":"dung nhập thân thể","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1859","loai":"xuất hiện","importance":"normal","giaiDoan":"Dung nhập thân thể","text":"Vương Lâm lấy hồn làm vật dẫn, dùng phân thân trong pháp tắc Tiên Cương dung nhập thân thể để tiếp tục xông tầng cao.","anchor":"Phân thân, lấy hồn làm vật dẫn, dung nhập thân thể"}]},"capNhatToi":"@c1859","nguon":["@c1859"]},{"id":"mot-chi-chin-muoi-chin-dao-hu-anh","name":"Một chỉ chín mươi chín đạo hư ảnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông một chỉ do Vương Lâm thi triển trong Thiên Tôn Niết, hiện ra chín mươi chín đạo hư ảnh hợp thành ngón tay khổng lồ.","detail":"Vương Lâm dùng một chỉ này nhằm đánh vào Truyền Tống Trận cổ xưa, không phải để làm Minh Đạo Tôn bị thương mà để buộc hắn bước ra khỏi quá trình truyền tống và tiếp tục cuộc tỷ thí tầng mười bảy.","congNang":["Ép đối thủ rời Truyền Tống Trận khi được dùng để phá ngang quá trình truyền tống @c1860"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1860","loai":"thi triển","importance":"normal","giaiDoan":"Ép Minh Đạo Tôn quay lại","text":"Vương Lâm điểm một chỉ, chín mươi chín hư ảnh hợp thành ngón tay khổng lồ lao tới Truyền Tống Trận cổ xưa để buộc Minh Đạo Tôn bước ra.","anchor":"Một chỉ này bất ngờ có chín mươi chín đạo hư ảnh biến ảo ra"}]},"capNhatToi":"@c1860","nguon":["@c1860"]},{"id":"than-thong-bien-nguoi-cua-hai-long","name":"Thần thông biến người của Hải Long","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cổ xưa","hePhai":"","soHuu":["Hải Long"],"blurb":"Thần thông cổ xưa giúp Hải Long biến thành người.","detail":"Hải Long nói mình học được thần thông này ở một địa phương cổ xưa, nhờ đó có thể hóa thành hình người để giải thích với Lưu Kim Bưu.","nguon":["@c1862"],"thuocTinh":"biến hóa","congNang":["Giúp Hải Long biến thành người @c1862"],"nguoiTu":[{"ten":"Hải Long","tuChuong":"@c1862","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1862","loai":"xuất hiện","importance":"normal","giaiDoan":"được Hải Long nhắc tới","text":"Hải Long giải thích rằng mình từng học một loại thần thông cổ xưa giúp biến thành người.","anchor":"ta từ một địa phương cố xưa học được một loại thần thông"}]},"capNhatToi":"@c1862"},{"id":"thu-thuat-xoa-bop-duong-manh-thu","name":"Thủ thuật xoa bóp dưỡng mãnh thú","cn":"","loai":"khac","loaiLabel":"Thủ thuật","phamCap":"không rõ","hePhai":"tông môn chuyên nuôi dưỡng mãnh thú","soHuu":["Lưu Kim Bưu"],"blurb":"Thủ thuật xoa bóp dùng để kích thích huyết mạch mãnh thú và khiến chúng thoải mái.","detail":"Lưu Kim Bưu nói thủ thuật này do một tông môn chuyên nuôi dưỡng mãnh thú truyền ra ở Động phủ giới. Hắn dùng nó để làm Hải Long thư thái, từ đó dụ Hải Long phun nguyên thần khí cho mình hấp thu.","nguon":["@c1862"],"thuocTinh":"xoa bóp, dưỡng thú","congNang":["Kích thích huyết mạch mãnh thú lưu thông nhanh @c1862","Dụ Hải Long thả lỏng để phun nguyên thần khí @c1862"],"nguoiTu":[{"ten":"Lưu Kim Bưu","tuChuong":"@c1862","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1862","loai":"thi triển","importance":"normal","giaiDoan":"dùng trong động phủ","text":"Lưu Kim Bưu thi triển thủ thuật xoa bóp học ở Động phủ giới để dụ Hải Long phun nguyên thần khí.","anchor":"Đây là một thủ thuật xoa bóp do một tông môn chuyên nuôi dường mãnh thú"}]},"capNhatToi":"@c1862"},{"id":"uy-ap-khien-van-vat-bat-dong-cua-dao-nhat","name":"Uy áp khiến vạn vật bất động của Đạo Nhất","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / uy áp Đại Thiên Tôn","phamCap":"Đại Thiên Tôn","hePhai":"Đạo Nhất","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Uy áp do chân thân Đạo Nhất phóng ra khi giáng lâm, khiến thiên địa vạn vật như bị đóng băng.","detail":"Khi Đạo Nhất chân thân xuất hiện, gió, cây cối, y phục và cả thiên địa quanh khu vực đều trở nên bất động. Vương Lâm là người nhanh chóng khôi phục trong uy áp này, khiến Đạo Nhất kinh ngạc và thừa nhận vị thế của hắn dưới Đại Thiên Tôn.","thuocTinh":"Uy áp Đại Thiên Tôn","uyLuc":"Có thể khiến thiên địa vạn vật trong phạm vi xuất hiện rơi vào trạng thái bất động.","dacDiem":"Tác dụng trực tiếp lên không gian và vạn vật quanh nơi chân thân Đạo Nhất giáng lâm.","trangThai":"Đã thi triển","capNhatToi":"@c1863","congNang":["Đóng băng vạn vật trong phạm vi Đạo Nhất chân thân xuất hiện @c1863"],"nguoiTu":[{"ten":"Đạo Nhất Đại Thiên Tôn","tuChuong":"@c1863","tangDatToi":"","trangThai":"thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c1863","loai":"thi triển","importance":"normal","giaiDoan":"Chân thân Đạo Nhất giáng lâm","text":"Đạo Nhất dùng uy áp khiến thiên địa vạn vật yên tĩnh và bất động khi xuất hiện trước Vương Lâm.","anchor":"Thân ảnh Đạo Nhất biến ảo ra, thiên địa vạn vật chợt yên tĩnh."}]},"nguon":["@c1863"]},{"id":"dao-tinh-do-dao-niem-hoa-thanh","name":"Đạo tinh do đạo niệm hóa thành","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đạo niệm của Đại Thiên Tôn","hePhai":"Đạo Nhất Đại Thiên Tôn","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Thần thông của Đạo Nhất ngưng đạo niệm thành đạo tinh để tạo ràng buộc bảo hộ một chiều cho người được dung nhập.","detail":"Đạo Nhất nói vật này do đạo niệm của bản thân biến thành. Nếu Vương Lâm dung nhập và tử vong thì Đạo Nhất sẽ bị thương, còn nếu Đạo Nhất chết thì Vương Lâm không bị ảnh hưởng.","thuocTinh":"Đạo niệm, bảo hộ đơn phương","nguonGoc":"Do đạo niệm của Đạo Nhất Đại Thiên Tôn hóa thành","uyLuc":"Có thể khiến kẻ động vào người mang đạo tinh trở thành địch nhân của Đạo Nhất.","dacDiem":"Ràng buộc sinh tử một chiều, chỉ khiến Đạo Nhất chịu tổn thương khi người được bảo hộ tử vong.","congNang":["Bảo hộ người dung nhập bằng uy danh và ràng buộc với Đạo Nhất @c1864","Khi người được dung nhập tử vong, Đạo Nhất sẽ bị thương @c1864"],"nguoiTu":[{"ten":"Đạo Nhất Đại Thiên Tôn","tuChuong":"@c1864","tangDatToi":"Ngưng đạo niệm thành đạo tinh","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1864","loai":"xuất hiện","importance":"normal","giaiDoan":"Đạo Nhất đưa điều kiện mời chào","text":"Đạo Nhất lấy đạo niệm hóa thành đạo tinh và dùng nó làm cam kết bảo hộ Vương Lâm.","anchor":"nếu ngươi tử vong thì bổn tôn sẽ bị thương"}]},"capNhatToi":"@c1864","nguon":["@c1864"]},{"id":"luc-luong-cuu-duong","name":"Lực lượng Cửu Dương","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp Đại Thiên Tôn","hePhai":"Song Tử Đại Thiên Tôn","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Lực lượng do Song Tử Đại Thiên Tôn triển khai thành kim quang áp đảo trên đại lục Tiên Tộc.","detail":"Song Tử Đại Thiên Tôn dùng lực lượng Cửu Dương tạo kim quang như mặt trời, khiến Đạo Nhất, Võ Phong và Cửu Đế phải rút lui vì không muốn liều mạng dùng lực lượng này trên đại lục Tiên Tộc.","thuocTinh":"Kim quang áp đảo","uyLuc":"Ép ba Đại Thiên Tôn rút lui khỏi cuộc tranh mời Vương Lâm.","dacDiem":"Triển khai trên đại lục Tiên Tộc khiến các Đại Thiên Tôn khác phải tránh xung đột trực tiếp.","congNang":["Tạo kim quang áp đảo và bức lui đối thủ cấp Đại Thiên Tôn @c1865"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1865","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1865","loai":"thi triển","importance":"normal","giaiDoan":"Song Tử ép ba Đại Thiên Tôn rút lui","text":"Song Tử triển khai lực lượng Cửu Dương trên đại lục Tiên Tộc, dùng kim quang khiến Đạo Nhất, Võ Phong và Cửu Đế phải rút lui.","anchor":"Rõ là hai đứa bé vô pháp vô thiên, lại triển khai lực lượng Cửu Dương trên đại lục của Tiên Tộc."}]},"trangThai":"đang lưu truyền qua Song Tử","capNhatToi":"@c1865","nguon":["@c1865"]},{"id":"than-thong-dua-nguoi-khoi-dong-phu-gioi-cua-song-tu","name":"Thần thông đưa người khỏi động phủ giới của Song Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Song Tử Đại Thiên Tôn","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Khả năng đặc biệt của Song Tử Đại Thiên Tôn trong việc đưa người khỏi động phủ giới.","detail":"Vương Lâm nhận ra Song Tử Đại Thiên Tôn có thể mang Tham Lang, người có tu vi không cao, ra khỏi động phủ giới mà dường như không tốn sức. Điều này vượt ngoài giới hạn mà hắn từng biết từ Huyền La.","thuocTinh":"Liên quan động phủ giới","uyLuc":"Có thể đưa Tham Lang khỏi động phủ giới mà dường như không cần tốn sức.","dacDiem":"Được Vương Lâm xem là điểm đặc biệt khiến Song Tử có giá trị khác hẳn các Đại Thiên Tôn khác.","congNang":["Đưa người khỏi động phủ giới @c1865"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1865","tangDatToi":"","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1865","loai":"nhắc tới","importance":"normal","giaiDoan":"Vương Lâm nhận ra năng lực","text":"Từ việc Tham Lang bị đưa khỏi động phủ giới, Vương Lâm nhận ra Song Tử có năng lực đặc biệt liên quan nơi này.","anchor":"Nhưng Tham Lang này tu vi không cao lại bị Song Tử Đại Thiên Tôn mang ra khỏi động phủ giới mà dường như không cần tốn chút sức lực!"}]},"trangThai":"đang thuộc Song Tử","capNhatToi":"@c1865","nguon":["@c1865"]}]};
